def allow_basic_formatting(text):
    if not text:
        return ""
    text = escape(text)
    replacements = [
        ("&lt;b&gt;", "<strong>"),
        ("&lt;/b&gt;", "</strong>"),
        ("&lt;strong&gt;", "<strong>"),
        ("&lt;/strong&gt;", "</strong>"),
        ("&lt;i&gt;", "<em>"),
        ("&lt;/i&gt;", "</em>"),
        ("&lt;em&gt;", "<em>"),
        ("&lt;/em&gt;", "</em>"),
        ("<br>", "<br>"),
        ("<br/>", "<br>"),
        ("<br />", "<br>"),
    ]
    for old, new in replacements:
        text = text.replace(old, new)
    return text

@app.route("/")
def dashboard():
    name = request.args.get("name", "Guest").strip() or "Guest"
    bio = request.args.get("bio", "").strip()
    location = request.args.get("location", "").strip()
    status = request.args.get("status", "").strip()

    initials = "".join(part[0] for part in name.split()[:2]).upper() or "G"

    return render_template_string(
        DASHBOARD_TEMPLATE,
        name=escape(name),
        initials=escape(initials),
        bio_html=allow_basic_formatting(bio) if bio else "<span class='empty'>No bio provided.</span>",
        location=escape(location),
        status_html=allow_basic_formatting(status) if status else "<span class='empty'>No status provided.</span>",
        status_plain=escape(status),
        status=status,
    )

if __name__ == "__main__":
    app.run(debug=True)